//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    const codeOptions = [
        { grpCd: "SD166", compID: "acb_apprvStsClsCd,gr_approveList:estApprvStsClsCd" } // 결재상태
    ]
    $c.data.setCommonCode(codeOptions);

    scwin.f_defaultValue();
    tbx_totalRows.setValue(0);
};

//-------------------------------------------------------------------------
// 날짜설정
//-------------------------------------------------------------------------
scwin.f_SetDate = function (pSetType) {
    //유형 1:현재일 7일전  , 2:현재일 , 3:이후일
    var vReturnDate = "";

    if (pSetType == "1") {
        vReturnDate = new Date().before(0, 0, 7).format("YYYYMMDD");
    } else if (pSetType == "2") {
        vReturnDate = new Date().format("YYYYMMDD");
    } else if (pSetType == "3") {
        vReturnDate = new Date().format("YYYYMM");
    } else if (pSetType == "4") {
        vReturnDate = new Date().before(0, 0, 30).format("YYYYMMDD");
    }

    return vReturnDate;
}

//-------------------------------------------------------------------------
// 검색 조건 데이타 셋 초기화 
