//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // f_chkOpenCommonPopUp(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);
    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj)
    let pCode = ''
    let pName = ''
    let pClose = 'T'
    let pAllSearch = 'T'

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode === true) {
        pCode = (pVal || "").trim();
    } else {
        pName = pVal || "";
    }

    switch (disGubun) {
        case 1:
            udc_cstmrNo.cfCommonPopUp(scwin.udc_cstmrNo_callBackFunc,
                pCode, pName, pClose,
                null, null, null, null, null, null, null, null, null, null,
                pAllSearch, null);
            break;

        case 2:
            udc_empNo.cfCommonPopUp(
                scwin.udc_empNo_callBackFunc,
                (pCode || "").trim(),
                pName,
                pClose,
                null,
                null,
                "150,176",
                "3,4,5,6,7,8,9,10",
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "사원팝업, 사원번호, 사원명",
                null
            );
            break;

        case 3:
            udc_estBranCd.cfCommonPopUp(scwin.udc_estBranCd_callBackFunc,
                pCode, pName, pClose,
                null, null, null, null, null, null, null, null, null, null,
                pAllSearch, null);
            break;
    }
}



