scwin.f_RequestElectronicApprovePopUp = async function (e) {
    ////////////////////////////////////////////////////////////////////////////
    var checkedRow = -1;
    var count = 0;

    for (let i = 0; i < ds_approveList.getRowCount(); i++) {
        if (ds_approveList.getCellData(i, "chk") == "1") {
            count++;
            checkedRow = i;
        }
    }
    ////////////////////////////////////////////////////////////////////////////

