    ds_approveList.setRowPosition(rowIndex);

    var valueObject = {
        estNo: ds_approveList.getCellData(rowIndex, "estNo"),
        estDblClick: "1"
    };

    const opts = {
        id: "sd_201_02_09p",
        popupName: "견적전자결재 상세",
        width: "820px",
        height: "520px",
        modal: true,
        scrollbars: "no",
        resizable: false
    };

    $c.win.openPopup("./sd_201_02_09p.xml", opts, valueObject);
};


